INSERT INTO `achievements` VALUES (10,'Champion in Debate for Democracy!','champion-in-debate-for-democracy',NULL,'<p>DCGPSC debate team became champion in Debate for Democracy parliamentary debate defeating Saint Joseph College in the final.&nbsp;</p>',NULL,'https://drive.google.com/file/d/1mfT1C2Fk3No-08x0PVzjo5zjwYesiynU/view?usp=sharing',NULL,'barisal-admin','2025-02-23 05:37:07',1,0,'2026-03-24 23:38:20','2026-03-24 23:42:25'),(11,'National Champion in Wildlife Olympiad!','national-champion-in-wildlife-olympiad',NULL,'<p>Zerin Tasnim, a student of class XII of this college, became the champion in Wildlife Olympiad 2024 at National level. Heartiest congratulations to her and her parents from DCGPSC family on this outstanding achievement.</p>',NULL,'https://drive.google.com/file/d/1BKEveMoZvlg9DsGp5nlK-3frE0UzTmc9/view?usp=sharing',NULL,'barisal-admin','2024-11-10 00:38:20',1,0,'2026-03-24 23:40:23','2026-03-24 23:43:02'),(12,'Outstanding Result in HSC 2024!','outstanding-result-in-hsc-2024',NULL,'<p>Out of 536 students, 534 passed and 306 achieved GPA 5.00.</p><p>Congrats to the successful students and their parents from DCGPSC family!</p>',NULL,'https://drive.google.com/file/d/1ydTYVMiipFx7sZTGYam9qhVH2ZgKQPqH/view?usp=sharing',NULL,'barisal-admin','2024-10-15 05:40:23',1,0,'2026-03-24 23:41:38','2026-03-24 23:43:24'),(13,'Great Achievements in Neutropedia 2.0 Fest!','great-achievements-in-neutropedia-20-fest',NULL,'<p>We are delighted to share the remarkable achievements of our students at the Neutropedia 2.0 Fest organized by BAFSDGT. Our students performed exceptionally well, and their hard work has paid off. Here are the highlights -</p><ul><li><strong>Green Pitch:</strong> Runner-up</li><li><strong>Wall Magazine:</strong> Champions</li><li><strong>Quiz: </strong>1st and 2nd Place</li><li><strong>Extempore Speech:</strong> Runner-up</li></ul><p>And, our students secured <strong>2nd place in the essay competition at BUET Environment Fest </strong>on June 10th.</p><p>Congratulations to all the successful students and teams from DCGPSC Family!</p>','https://drive.google.com/file/d/1fDh_O9usvkheCJ-UEvxcvGuRwR3wUoaC/view?usp=sharing','https://drive.google.com/file/d/1fDh_O9usvkheCJ-UEvxcvGuRwR3wUoaC/view?usp=sharing',NULL,'barisal-admin','2024-06-13 02:48:41',1,0,'2026-03-30 21:05:00','2026-03-30 21:40:34'),(15,'Outstanding Result in SSC - 2024','outstanding-result-in-ssc-2024',NULL,'<p>SSC Result 2024!</p><p>162 Students achieved GPA of 5.00 in SSC Examination.</p><p>Congrats to the successful student and their parents!</p>',NULL,'https://drive.google.com/file/d/12yY-7GLvsgF3uNaSNB66p3bDGdIBwV1t/view?usp=sharing',NULL,'barisal-admin','2024-03-31 03:09:43',1,0,'2026-03-30 21:10:15','2026-03-30 21:35:32'),(16,'Outstanding Result in SSC - 2023','outstanding-result-in-ssc-2023',NULL,'<p>Students brought out another glorious result in SSC - 2023. 126 Out of 177 students achieved GPA 5.00 with 100% pass rate. 10 out of 36 students secured GPA 5.00 in Business Studies group and 116 out of 141 students secured GPA 5.00 in Science group.</p><p>Congrats</p><p>to the successful students and guardians from DCGPSC family!</p>',NULL,'https://drive.google.com/file/d/1p7wsr2hrNQ1veklo3In3S_vMNTrJNFyX/view?usp=sharing',NULL,'barisal-admin','2023-08-28 03:10:15',1,0,'2026-03-30 21:11:59','2026-03-30 21:35:25'),(17,'First position in `Bangabandhu Srijonshil Medha Onneshon 2023`!','first-position-in-bangabandhu-srijonshil-medha-onneshon-2023',NULL,'<p>Samailah Tazrian, a student of class VIII, secured first position in \'Bhasha O Sahitya\' category in \'Bangabandhu Srijonshil Medha Onneshon 2023\' in VI to VIII group in Dhaka division.</p><p>Congrats to Samailah and her family!</p>',NULL,'https://drive.google.com/file/d/1HV_ESe-CkY5WTXwiySyImUqqn1owKY71/view?usp=sharing',NULL,'barisal-admin','2023-03-15 03:11:59',1,0,'2026-03-30 21:13:05','2026-03-30 21:35:08'),(18,'Outstanding result in HSC - 2022!','outstanding-result-in-hsc-2022',NULL,'<p>307 students got GPA 5.00 in HSC - 2022. 278 students in Science group and 29 students in Business Studies group achieved GPA 5.00. 450 students out of 451 passed.</p><p>Congrats to the successful students!</p>',NULL,'https://drive.google.com/file/d/1QiJuGbfHuP-Fq_GiQH2IZIiOSGdNYHVs/view?usp=sharing',NULL,'barisal-admin','2023-01-11 03:13:05',1,0,'2026-03-30 21:14:09','2026-03-30 21:39:10'),(19,'Champion in Badminton Singles!','champion-in-badminton-singles',NULL,'<p>One of our students became champion in Cantonment Thana \'Inter School Badminton Tournament - 2023\' in the singles.</p><p>Congrats to her!</p>',NULL,'https://drive.google.com/file/d/1PIg7jbPtoof3cJIkfZhgailw0U17Ki3r/view?usp=sharing',NULL,'barisal-admin','2023-01-11 03:14:09',1,0,'2026-03-30 21:15:30','2026-03-30 21:39:40'),(20,'Runners up in Basketball Tournament!','runners-up-in-basketball-tournament',NULL,'<p>DCGPSC Basketball team became runners up in the Cantonment Thana \'Inter School Basketball Competition - 2023\'.</p><p>Congrats to the successful team!</p>',NULL,'https://drive.google.com/file/d/1B9GoWv1cFXmJZrda8OKC-0wka4Woo8Xo/view?usp=sharing',NULL,'barisal-admin','2023-01-11 03:15:30',1,0,'2026-03-30 21:16:45','2026-03-30 21:32:51'),(21,'3 Students Awarded Scholarship in SSC – 2022!','3-students-awarded-scholarship-in-ssc-2022',NULL,'<p>3 of our students have awarded scholarship based on the result of SSC - 2022! They are -</p><p>105816 Maisha Binte Ahmad (Talent Pool)</p><p>105769 Nusratun Islam Neha (General Grade)</p><p>105771 Mahia Islam Shuci (General Grade)</p><p>Congratulations to them and their family for the wonderful result!</p>',NULL,'https://drive.google.com/file/d/1Yc46hPhQP5ekG5YwS_CAIwl--u7bZoIe/view?usp=sharing',NULL,'barisal-admin','2022-12-29 03:16:45',1,0,'2026-03-30 21:17:43','2026-03-30 21:37:43'),(22,'Outstanding Result in SSC - 2022!','outstanding-result-in-ssc-2022',NULL,'<p>Outstanding result in SSC - 2022</p><p>Passed 100%.</p><p>In Science Group GPA 5: 132 (Out of 135)</p><p>Business Studies Group GPA 5: 29 (Out of 49)</p><p>Congratulations to the successful students, their guardians, and all the teachers!</p>',NULL,'https://drive.google.com/file/d/1phCh5guiLO6CDrS3yF36NwPTlaGyzT0D/view?usp=sharing',NULL,'barisal-admin','2022-03-31 03:17:43',1,0,'2026-03-30 21:18:37','2026-03-30 21:32:05'),(23,'Outstanding Result is HSC - 2021!','outstanding-result-is-hsc-2021',NULL,'<p>Students brought out an outstanding result in HSC examination - 2021! All passed out of 272 students and 177 students obtained GPA 5.00! Congratulations to the successful students, their guardians, and all teachers for this brilliant success.&nbsp;</p>',NULL,'https://drive.google.com/file/d/1wvrWgq3jiAOdX7qZIbFare7lDlBT6ZM7/view?usp=sharing',NULL,'barisal-admin','2021-03-17 03:18:37',1,0,'2026-03-30 21:19:47','2026-03-30 21:31:47'),(24,'Outstanding Result is SSC - 2021!','outstanding-result-is-ssc-2021',NULL,'<p>Students brought out another glorious result in SSC Examination. In SSC - 2021, 113 students out of 159 students achieved GPA 5.00. In Science group 102 out of 118 students achieved GPA 5.00 while 11 out of 41 students achieved GPA 5.00. Pass percentage is 100%.</p><p>Congratulations to the successful students, their guardians and teachers for the brilliant success!</p>',NULL,'https://drive.google.com/file/d/1NMukX1qe2axkIVCUfefSZkLMUjn4ypTB/view?usp=sharing',NULL,'barisal-admin','2021-08-15 03:19:47',1,0,'2026-03-30 21:21:12','2026-03-30 21:31:02'),(25,'Outstanding Result in SSC - 2020!','outstanding-result-in-ssc-2020',NULL,'<p>Students brought out another outstanding result in SSC - 2020. 98 students out of 153 achieved GPA 5.00. Here are the result statistics is in the attached image.&nbsp;</p><p><br><br></p>',NULL,'https://drive.google.com/file/d/1oFpvyZHvn9xqEZ8EZMBpktT4MuH3Wrg7/view?usp=sharing',NULL,'barisal-admin','2020-05-30 03:21:12',1,0,'2026-03-30 21:22:09','2026-03-30 21:30:36');
/*!40000 ALTER TABLE `achievements` ENABLE KEYS */;
