:{i:0;s:17:\"homepage_template\";i:1;s:13:\"sidebar_title\";i:2;s:17:\"news_events_title\";i:3;s:18:\"achievements_title\";i:4;s:17:\"all_notices_title\";i:5;s:13:\"primary_color\";i:6;s:15:\"secondary_color\";i:7;s:12:\"accent_color\";i:8;s:10:\"text_color\";i:9;s:10:\"link_color\";i:10;s:15:\"topbar_bg_color\";i:11;s:15:\"header_bg_color\";i:12;s:15:\"navbar_bg_color\";i:13;s:18:\"navbar_hover_color\";i:14;s:15:\"footer_bg_color\";i:15;s:22:\"footer_bottom_bg_color\";i:16;s:13:\"body_bg_color\";i:17;s:15:\"ticker_bg_color\";i:18;s:17:\"ticker_text_color\";i:19;s:19:\"message_card_design\";i:20;s:21:\"message_card_bg_image\";i:21;s:28:\"message_card_bg_image_gdrive\";i:22;s:17:\"card_header_color\";i:23;s:20:\"card_name_text_color\";i:24;s:27:\"card_designation_text_color\";i:25;s:23:\"card_image_border_color\";i:26;s:20:\"card_button_bg_color\";i:27;s:22:\"card_button_text_color\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}}',1776251365),('laravel-cache-global.welcome_section','O:25:\"App\\Models\\WelcomeSection\":33:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:16:\"welcome_sections\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:9:{s:2:\"id\";i:1;s:5:\"title\";s:53:\"Welcome to Dhaka Cantt Girls\' Public School & College\";s:7:\"content\";s:2318:\"Welcome to the website of Dhaka Cantonment Girls’ Public School and College. Our institution is dedicated to nurturing academically accomplished young women with highly developed interpersonal skills and a broad range of interests. We aim to equip our students to compete at the highest levels, both nationally and internationally, alongside the brightest and the best.\nWe are committed to providing excellent teaching and a dynamic program of extracurricular opportunities in a happy, vibrant atmosphere where every girl is encouraged to achieve her full potential. We value your feedback on our development and welcome any ideas for improvement. If you have suggestions, please email us and let us know.\n\nDhaka Cantonment Girls’ Public School & College is one of the most reputed institutions in Dhaka Cantonment. Nestled in a serene and picturesque environment, away from the hustle and bustle of the city, the college embarked on its journey in mid-2005.\nThe college offers both Bangla and English versions of study, allowing students to choose between Science and Business Studies. Each version has its own spacious building, including the pre-primary, school, and college sections. All classrooms are equipped with multimedia projectors and audio systems. Recently, a central public address system was installed for important announcements to students and teachers. Additionally, a large LED display has been installed in the college auditorium for conducting classes, presentations, and cultural programs.\nIn addition to ample classrooms, the college boasts four science laboratories and a well-stocked library. The two computer labs are fully air-conditioned and equipped with modern computers.\n\nThe institution supports extracurricular activities through its 14 clubs, including the Debate Club, English Language Club, Bangla Language and Literature Club, Arabic Language Club, Cultural Club, Sports Club, Science Club, Business Club, Math Olympiad Club, Nature Study Club, ICT Club, Art Club, Taekwondo Club, and Bangladesh National Cadet Corps club. Students are divided into four houses—Taramon Bibi House, Jahanara Imam House, Begum Rokeya House, and Begum Sufia Kamal House—for both academic and extracurricular activities. The institution has achieved remarkable success in a short span of time.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1Zg2u57qunWNrkt5yAi03qYjGfZGFkqUe/view?usp=sharing\";s:11:\"button_text\";s:8:\"Details \";s:10:\"button_url\";s:29:\"https://bacpsc.edu.bd/details\";s:9:\"is_active\";i:1;s:10:\"created_at\";s:19:\"2025-11-22 19:33:10\";s:10:\"updated_at\";s:19:\"2026-03-16 10:25:55\";}s:11:\"\0*\0original\";a:9:{s:2:\"id\";i:1;s:5:\"title\";s:53:\"Welcome to Dhaka Cantt Girls\' Public School & College\";s:7:\"content\";s:2318:\"Welcome to the website of Dhaka Cantonment Girls’ Public School and College. Our institution is dedicated to nurturing academically accomplished young women with highly developed interpersonal skills and a broad range of interests. We aim to equip our students to compete at the highest levels, both nationally and internationally, alongside the brightest and the best.\nWe are committed to providing excellent teaching and a dynamic program of extracurricular opportunities in a happy, vibrant atmosphere where every girl is encouraged to achieve her full potential. We value your feedback on our development and welcome any ideas for improvement. If you have suggestions, please email us and let us know.\n\nDhaka Cantonment Girls’ Public School & College is one of the most reputed institutions in Dhaka Cantonment. Nestled in a serene and picturesque environment, away from the hustle and bustle of the city, the college embarked on its journey in mid-2005.\nThe college offers both Bangla and English versions of study, allowing students to choose between Science and Business Studies. Each version has its own spacious building, including the pre-primary, school, and college sections. All classrooms are equipped with multimedia projectors and audio systems. Recently, a central public address system was installed for important announcements to students and teachers. Additionally, a large LED display has been installed in the college auditorium for conducting classes, presentations, and cultural programs.\nIn addition to ample classrooms, the college boasts four science laboratories and a well-stocked library. The two computer labs are fully air-conditioned and equipped with modern computers.\n\nThe institution supports extracurricular activities through its 14 clubs, including the Debate Club, English Language Club, Bangla Language and Literature Club, Arabic Language Club, Cultural Club, Sports Club, Science Club, Business Club, Math Olympiad Club, Nature Study Club, ICT Club, Art Club, Taekwondo Club, and Bangladesh National Cadet Corps club. Students are divided into four houses—Taramon Bibi House, Jahanara Imam House, Begum Rokeya House, and Begum Sufia Kamal House—for both academic and extracurricular activities. The institution has achieved remarkable success in a short span of time.\";s:9:\"image_url\";s:82:\"https://drive.google.com/file/d/1Zg2u57qunWNrkt5yAi03qYjGfZGFkqUe/view?usp=sharing\";s:11:\"button_text\";s:8:\"Details \";s:10:\"button_url\";s:29:\"https://bacpsc.edu.bd/details\";s:9:\"is_active\";i:1;s:10:\"created_at\";s:19:\"2025-11-22 19:33:10\";s:10:\"updated_at\";s:19:\"2026-03-16 10:25:55\";}s:10:\"\0*\0changes\";a:0:{}s:11:\"\0*\0previous\";a:0:{}s:8:\"\0*\0casts\";a:1:{s:9:\"is_active\";s:7:\"boolean\";}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s:14:\"\0*\0observables\";a:0:{}s:12:\"\0*\0relations\";a:0:{}s:10:\"\0*\0touches\";a:0:{}s:27:\"\0*\0relationAutoloadCallback\";N;s:26:\"\0*\0relationAutoloadContext\";N;s:10:\"timestamps\";b:1;s:13:\"usesUniqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:6:{i:0;s:5:\"title\";i:1;s:7:\"content\";i:2;s:9:\"image_url\";i:3;s:11:\"button_text\";i:4;s:10:\"button_url\";i:5;s:9:\"is_active\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}}',1776251365),('laravel-cache-homepage.achievements','O:39:\"Illuminate\\Database\\Eloquent\\Collection\":2:{s:8:\"\0*\0items\";a:3:{i:0;O:22:\"App\\Models\\Achievement\":33:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\