INSERT INTO `news_events` VALUES (5,'Annual Sport - 2026','annual-sport-2026',NULL,'<p>The biggest event of the year, The Interhouse Annual Sport - 2026, took place in a festive mood. The campus took a colorful look for that event, so as the students. There were gaming events for the students, the parents, and the guests, Parade, PT, Taekwondo, Dress as You Like, and a colorful display. Major General Md Sajedur Rahman , ndu, psc, Military Secretary, Bangladesh Army, was present as the chief guest while Fatema Zohura was the special guest. The special guest distributed prizes among the winners, and the chief guest awarded the group champions and the winner houses.&nbsp;</p><p>The program ended with the attenuation of the flags.</p>','https://drive.google.com/file/d/1JRu5I8v4w1HLvh--h4NFUCihIZaBdczK/view?usp=sharing',NULL,'barisal-admin',1,'2026-01-21 23:26:42','2026-03-24 23:28:39','2026-03-24 23:44:19'),(6,'Celebrating the Outstanding HSC Results with our Student','celebrating-the-outstanding-hsc-results-with-our-student',NULL,'<p>Congratulations to all HSC achievers! Your hard work, patience, and dedication have paid off. Wishing you all the best for your next chapter!</p>','https://drive.google.com/file/d/1kBIoENKw_wXL2JVA1OEWs7tOY_j1K1HQ/view?usp=sharing',NULL,'barisal-admin',1,'2025-10-09 23:28:38','2026-03-24 23:31:11','2026-03-24 23:44:59'),(7,'Celebrating the Outstanding SSC Results with our Student','celebrating-the-outstanding-ssc-results-with-our-student',NULL,'<p>A proud moment for our school.</p><p>Celebrating the outstanding SSC results with our students, teachers and honourable Principal sir.</p><p>Congratulations to all students!</p>','https://drive.google.com/file/d/1oDl4njObYgi75w6L3zgGsSG_ukulT4yX/view?usp=sharing',NULL,'barisal-admin',1,'2025-07-09 23:31:10','2026-03-24 23:32:38','2026-03-24 23:45:24'),(8,'Outstanding Result in SSC - 2025','outstanding-result-in-ssc-2025',NULL,'<p>Students brought another brilliant result in SSC 2025. 143 out of 200 students achieved GPA 5.00 with 100% passed.</p><p>Result Summary</p><p>Science Group: Students - 160, GPA 5.00 - 133</p><p>Business Studies Group: Students - 40, GPA 5.00 - 10</p><p>Congratulations to all successful students, guardians, and the teachers for their continued efforts.</p>','https://drive.google.com/file/d/1AB-rhw4ZiRd3K7IyKZcDzSIjaIrMtSjh/view?usp=sharing',NULL,'barisal-admin',1,'2025-07-12 21:51:39','2026-03-30 21:53:41','2026-03-30 21:53:41'),(9,'Independence & National Day Observed','independence-national-day-observed',NULL,'<p>DCGPSC observed Independence &amp; National Day 2025 with due respect. The day was observed through a parade, reading the speeches of honorable president, chief advisor, and army chief, and discussion session.</p>','https://drive.google.com/file/d/1T1zbc5n38JtRRVMaH3hY9cH5ynt2OUf3/view?usp=sharing',NULL,'barisal-admin',1,'2025-03-25 21:53:41','2026-03-30 21:56:27','2026-03-30 21:56:27'),(10,'National Genocide Day Observed','national-genocide-day-observed',NULL,'<p>DCGPSC observed National Genocide Day with due respect. Freedom fighter Senior Warrant Officer Mizanur Rahman enlightened the students by telling stories of his experience in the liberation of Bangladesh in 1971.&nbsp;</p>','https://drive.google.com/file/d/1FTafYqU_7W-YjH9oYl66Bl2bs0Cwk2Eq/view?usp=sharing',NULL,'barisal-admin',1,'2025-03-25 21:56:27','2026-03-30 21:57:39','2026-03-30 21:57:39'),(11,'Teachers` Enrichment Program - 2025','teachers-enrichment-program-2025',NULL,'<p>ll teachers of DCGPSC participated in the Teachers\' Enrichment Program held between 9 to 12 March 2025.</p>','https://drive.google.com/file/d/1AyjLZZ6EDIaQVxu2QyIUffNaY2I7w6QN/view?usp=sharing',NULL,'barisal-admin',1,'2025-03-25 21:57:39','2026-03-30 21:59:25','2026-03-30 21:59:25'),(12,'Youth Fest - 2025','youth-fest-2025',NULL,'<p>DCGPSC organized a workshop on Social Business and Entrepreneurship in the Youth Fest - 2025! Some fellow young entrepreneurs encouraged the students in social business.&nbsp;</p>','https://drive.google.com/file/d/1Wyp_L9Jvci6TZLUzNNs2bphkvbaVNiKl/view?usp=sharing',NULL,'barisal-admin',1,'2025-03-25 21:59:25','2026-03-30 22:03:33','2026-03-30 22:03:33'),(13,'21 February, Shahid Dibosh, and Internal Mother Language Day Observed','21-february-shahid-dibosh-and-internal-mother-language-day-observed',NULL,'<p>DCGPSC observed 21 February, Shahid Dibosh, and Internal Mother Language Day with due respect. The day was observed through a provat ferri, doa, discussion, and a cultural program.&nbsp;</p>','https://drive.google.com/file/d/1AZhPN1qZvuMsEcGAVgskEaXLFqZJ2K-X/view?usp=sharing',NULL,'barisal-admin',1,'2026-03-30 22:03:33','2026-03-30 22:05:58','2026-03-30 22:05:58'),(14,'Kids Study Tour to Science Museum','kids-study-tour-to-science-museum',NULL,'<p>The study tour of class III, IV, and V took place in a festive mood. The students visited National Science Museum and explored the amazing world of science. <br><br>Click on the following links to get more photos - <br><a href=\"https://www.facebook.com/dcgpsc/posts/pfbid02EgQ58bWGocd3ajJutRWMnixkjVoR1RnfcrdrEQMF4FFocPri1W4Nc6bSPAv4HPNLl?__cft__[0]=AZWLwuEuoZrVpLpzVTh5klez_xsg08sg6nD21hDuaqDoebArEuSo9Trbnqy9sw2vV9vzzpCTNC2nGcex7gnyxxX-0jJW5OYGoDpKl_tbmz7rb6nEgMT3mC7-2reTV3U2EW5rR_LbE8AHi77MskaUiUq-G_HbVC2Tmk9CvnIx-A27CQ&amp;__tn__=%2CO%2CP-R\">Day 1 Photo Link </a><br><a href=\"https://www.facebook.com/dcgpsc/posts/pfbid02cE6BzxaRygiJXRDdRUCBM5ULWSgaRJd1PMtQn5NRzu7GGyk6Qit7Ykk1bt37FprQl?__cft__[0]=AZUdIa8k3f0eDiHbpvUSOx9adWaeYhm_SVOcdwl2LFPpx-pb6FBZwPJyYvGrWtt-BtEO-D0TmSllgnbN4cXv1cLTa5NJnXh5fzFBk9o0XPHSYkkmv5UWixYIHgCQ1Zxr-WCBAYTJxJfpCife1GF7ykmp4zzBEpemms5emeHQt572EA&amp;__tn__=%2CO%2CP-R\">Day 2 Photo Link</a>&nbsp;</p>','https://drive.google.com/file/d/1aRCMe5SFJZk5lTYjfjUmdQUCZxwM3Nqu/view?usp=sharing',NULL,'barisal-admin',1,'2026-03-25 22:05:58','2026-03-30 22:07:35','2026-03-30 22:07:35'),(15,'Bosnto Boron Utsob held','bosnto-boron-utsob-held',NULL,'<p>DCGPSC celebrated Bosonto Born Utsob with a colorful program that took place at the college playground.&nbsp;</p>','https://drive.google.com/file/d/1nSXoprzZf6FRlCIfrT7RoeERXYi4y85p/view?usp=sharing',NULL,'barisal-admin',1,'2025-03-25 22:07:35','2026-03-30 22:15:20','2026-03-30 22:15:20'),(16,'Nobinboron of Class XI Held','nobinboron-of-class-xi-held',NULL,'<p>Nobinboron of the students of class XI and Felicitation of the successful students of HSC 2023 who got admitted into different public universities and medical colleges was held in the college auditorium today. Brig Gen Md Abdur Razzak, SUP, ndc, psc, chairman, governing body, and, commander, 86 Independent Signal Brigade, was present as the chief guest while Mrs. Khadeza Chowdhury was the special guest. The newly admitted students of class XI were given warm reception with flowers and the successful students of HSC – 2023 were felicitated with crests. A colorful cultural program was also held performed by the students of class XII.<br><br></p>','https://drive.google.com/file/d/1WRRLf4MBvOz4RheEODM4e2jxUpvV4tpa/view?usp=sharing',NULL,'barisal-admin',1,'2024-10-07 22:15:20','2026-03-30 22:19:07','2026-03-30 22:19:07'),(17,'Eid Reunion Programme','eid-reunion-programme',NULL,'<p>A colourful Eid reunion programme was celebrated by the teachers and staffs of Dhaka Cantonment Girls\' Public School &amp; College. Honorable principal Col Md Mamun Azad Salehin, afwc, psc was the chief guest and Honorable ma\'am Salma Salehin was the special guest of this event. Various performances were performed by teachers and staff and they had a great day togethe</p>','https://drive.google.com/file/d/1mUJaie02CxUE9BnaJ9jRbXpLOsxbrXLE/view?usp=sharing',NULL,'barisal-admin',1,'2024-07-13 22:19:07','2026-03-30 22:21:02','2026-03-30 22:21:02'),(18,'Club Inauguration Ceremony 2024','club-inauguration-ceremony-2024',NULL,'<p>Club inauguration ceremony 2024:</p><p>Executive members from different newly formed clubs got the Sash and Arm Bands from our respected principal sir.</p>','https://drive.google.com/file/d/1s5bi97331YVVCY_5yzwbtRX4Qd6yN5ND/view?usp=sharing',NULL,'barisal-admin',1,'2024-07-07 22:21:02','2026-03-30 22:22:38','2026-03-30 22:22:38'),(19,'Testing Bucket','testing-bucket',NULL,'<p>Testing fgfdgfdgfdgdf</p>','https://pub-ef1e6cb91a354191aada31be868abf78.r2.dev/news-events/panchogarh-new-20260411071308.png',NULL,'barisal-admin',1,'2026-04-11 01:01:02','2026-04-11 01:02:15','2026-04-11 01:13:18'),(20,'Testing','testing',NULL,'<p>Hello</p>','https://pub-ef1e6cb91a354191aada31be868abf78.r2.dev/news-events/inshot-20250919-194143554-scaled-20260411080825.jpg',NULL,'barisal-admin',1,'2026-04-11 02:07:46','2026-04-11 02:08:46','2026-04-11 02:08:46');
