INSERT INTO `welcome_sections` VALUES (1,'Welcome to Dhaka Cantt Girls\' Public School & College','Welcome to the website of Dhaka Cantonment Girls’ Public School and College. Our institution is dedicated to nurturing academically accomplished young women with highly developed interpersonal skills and a broad range of interests. We aim to equip our students to compete at the highest levels, both nationally and internationally, alongside the brightest and the best.\nWe are committed to providing excellent teaching and a dynamic program of extracurricular opportunities in a happy, vibrant atmosphere where every girl is encouraged to achieve her full potential. We value your feedback on our development and welcome any ideas for improvement. If you have suggestions, please email us and let us know.\n\nDhaka Cantonment Girls’ Public School & College is one of the most reputed institutions in Dhaka Cantonment. Nestled in a serene and picturesque environment, away from the hustle and bustle of the city, the college embarked on its journey in mid-2005.\nThe college offers both Bangla and English versions of study, allowing students to choose between Science and Business Studies. Each version has its own spacious building, including the pre-primary, school, and college sections. All classrooms are equipped with multimedia projectors and audio systems. Recently, a central public address system was installed for important announcements to students and teachers. Additionally, a large LED display has been installed in the college auditorium for conducting classes, presentations, and cultural programs.\nIn addition to ample classrooms, the college boasts four science laboratories and a well-stocked library. The two computer labs are fully air-conditioned and equipped with modern computers.\n\nThe institution supports extracurricular activities through its 14 clubs, including the Debate Club, English Language Club, Bangla Language and Literature Club, Arabic Language Club, Cultural Club, Sports Club, Science Club, Business Club, Math Olympiad Club, Nature Study Club, ICT Club, Art Club, Taekwondo Club, and Bangladesh National Cadet Corps club. Students are divided into four houses—Taramon Bibi House, Jahanara Imam House, Begum Rokeya House, and Begum Sufia Kamal House—for both academic and extracurricular activities. The institution has achieved remarkable success in a short span of time.','https://drive.google.com/file/d/1Zg2u57qunWNrkt5yAi03qYjGfZGFkqUe/view?usp=sharing','Details ','https://bacpsc.edu.bd/details',1,'2025-11-22 13:33:10','2026-03-16 04:25:55');
/*!40000 ALTER TABLE `welcome_sections` ENABLE KEYS */;
UNLOCK TABLES;
